    '${(s.owner_name || '').replace(/'/g, "''")}',
    '${s.classification}',
    ${s.engagement_level || 0},
    ${s.days_in_stage || 0},
    '${metrics.replace(/'/g, "''")}'::jsonb,
    CURRENT_DATE
  )`;
}).join(',\n');

